#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int x, N;
        scanf("%d %d", &x, &N);
        long long sum = (long long)N * (N + 1) / 2 - x;
        if (sum % 2 != 0) {
            printf("impossible\n");
        } else {
            sum /= 2;
            int i;
            for (i = N; i > 0; i--) {
                if (i != x && sum >= i) {
                    sum -= i;
                }
            }
            if (sum != 0) {
                printf("impossible\n");
            } else {
                for (i = 1; i <= N; i++) {
                    if (i == x) {
                        printf("2");
                    } else if (i <= sum) {
                        printf("0");
                    } else {
                        printf("1");
                    }
                }
                printf("\n");
            }
        }
    }
    return 0;
}

