const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [x, N] = readline().split(' ').map(Number);
    let sum = (N * (N + 1) / 2) - x;
    if (sum % 2 !== 0) {
        console.log('impossible');
    } else {
        sum = Math.floor(sum / 2);
        let j = N;
        while (j > 0) {
            if (j !== x && sum >= j) {
                sum -= j;
            }
            j--;
        }
        if (sum !== 0) {
            console.log('impossible');
        } else {
            let result = '';
            for (let k = 1; k <= N; k++) {
                if (k === x) {
                    result += '2';
                } else if (k <= sum) {
                    result += '0';
                } else {
                    result += '1';
                }
            }
            console.log(result);
        }
    }
}

